import{_ as s,o as n,c as t,ae as o}from"./chunks/framework.BuvKvcPh.js";const i="/Furniture-Designer/images/design-fr.png",g=JSON.parse('{"title":"Conception 3D & Modélisation","description":"","frontmatter":{},"headers":[],"relativePath":"fr/design.md","filePath":"fr/design.md"}'),r={name:"fr/design.md"};function a(l,e,u,c,m,d){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="conception-3d-modelisation" tabindex="-1">Conception 3D &amp; Modélisation <a class="header-anchor" href="#conception-3d-modelisation" aria-label="Permalink to &quot;Conception 3D &amp; Modélisation&quot;">​</a></h1><p>Le <strong>Meuble Designer</strong> repose sur un concept de partitionnement spatial récursif. Au lieu de dessiner des planches une par une sur un croquis, vous définissez des volumes fonctionnels, et la géométrie algorithmique résout elle-même les intersections et l&#39;épaisseur des planches. Cela garantit que votre meuble reste mathématiquement parfait et physiquement viable à tout moment.</p><p><img src="'+i+'" alt="Interface Conception"></p><h2 id="contraintes-globales" tabindex="-1">Contraintes Globales <a class="header-anchor" href="#contraintes-globales" aria-label="Permalink to &quot;Contraintes Globales&quot;">​</a></h2><p>Votre conception commence par définir les limites absolues du caisson :</p><ul><li><strong>Dimensions Extérieures</strong> : Largeur, hauteur et profondeur totales du meuble.</li><li><strong>Épaisseur du Matériau</strong> : L&#39;épaisseur du bois est appliquée uniformément sur toutes les planches. Modifiez-la, et tous les compartiments intérieurs se recalculent dynamiquement pour compenser.</li></ul><h2 id="creation-de-compartiments" tabindex="-1">Création de Compartiments <a class="header-anchor" href="#creation-de-compartiments" aria-label="Permalink to &quot;Création de Compartiments&quot;">​</a></h2><p>En sélectionnant n&#39;importe quel nœud 3D (soit en cliquant directement sur le modèle 3D, soit en le sélectionnant via l&#39;arborescence de gauche), vous pouvez scinder l&#39;espace :</p><ul><li><strong>Rangées (Rows / Horizontaux)</strong> : Découpe l&#39;espace vertical disponible.</li><li><strong>Colonnes (Cols / Verticaux)</strong> : Découpe l&#39;espace horizontal disponible.</li></ul><p>Vous pouvez imbriquer des colonnes dans des rangées à l&#39;infini.</p><h2 id="controle-avance-des-dimensions" tabindex="-1">Contrôle Avancé des Dimensions <a class="header-anchor" href="#controle-avance-des-dimensions" aria-label="Permalink to &quot;Contrôle Avancé des Dimensions&quot;">​</a></h2><p>Le logiciel répartit par défaut l&#39;espace de manière égale.</p><ul><li><strong>Verrouillage des Cotes 🔒</strong> : Vous pouvez verrouiller la dimension d&#39;un compartiment (en millimètres) pour garantir qu&#39;il ne se redimensionnera pas tout seul. C&#39;est crucial lorsque vous concevez une niche pour un amplificateur qui doit faire exactement 430mm de large.</li><li><strong>Égaliser les Tailles ⚖</strong> : Si vous avez ajouté ou supprimé un casier, cliquez sur &quot;Égaliser&quot; pour redistribuer équitablement l&#39;espace restant entre vos compartiments non verrouillés.</li><li><strong>Redimensionnement Intelligent</strong> : Si vous modifiez manuellement la taille d&#39;un compartiment non verrouillé, le logiciel va automatiquement &quot;voler&quot; l&#39;espace de son voisin non verrouillé le plus proche. Les dimensions extérieures du meuble ne sont jamais brisées.</li></ul><h2 id="calques-objets-temoins" tabindex="-1">Calques &amp; Objets Témoins <a class="header-anchor" href="#calques-objets-temoins" aria-label="Permalink to &quot;Calques &amp; Objets Témoins&quot;">​</a></h2><p>L&#39;interface propose des outils visuels puissants :</p><ul><li><strong>Cotes (Quotes)</strong> : Affichez les mesures absolues directement sur la vue 3D.</li><li><strong>Verrous (Locks)</strong> : Souligne visuellement les compartiments dont les dimensions sont rendues rigides.</li><li><strong>Objets Témoins</strong> : Faites apparaître des objets de référence 3D à l&#39;échelle dans vos compartiments (ex: <strong>TV 55&quot;</strong>, <strong>Xbox Series X</strong>, <strong>Platine Vinyle</strong> ou <strong>Panier IKEA Kallax</strong>). Ces maquettes vous garantissent que vos affaires rentreront de manière certaine !</li></ul>',16)])])}const h=s(r,[["render",a]]);export{g as __pageData,h as default};
